});

function calculateDiscount(amount) {
  if (amount < 0) throw new Error('Invalid amount');
  if (amount >= 1000) return amount * 0.20;
  if (amount >= 500) return amount * 0.10;
  return 0;
}

describe('calculateDiscount', () => {
  test('rejects negative amount', () => {
    expect(() => calculateDiscount(-1)).toThrow('Invalid amount');
  });

  test('returns no discount below 500', () => {
    expect(calculateDiscount(499)).toBe(0);
  });

  test('returns 10 percent at boundary 500', () => {
    expect(calculateDiscount(500)).toBe(50);
  });

  test('returns 20 percent at boundary 1000', () => {
    expect(calculateDiscount(1000)).toBe(200);
  });
});

